#include <stdio.h>
int max(int a, int b) { return a > b ? a : b; }
int cutRibbon(int n, int a, int b, int c) {
    int dp[n + 1];
    dp[0] = 0;
    for (int i = 1; i <= n; i++) {
        dp[i] = -1;
        if (i >= a) dp[i] = max(dp[i], dp[i - a] + 1);
        if (i >= b) dp[i] = max(dp[i], dp[i - b] + 1);
        if (i >= c) dp[i] = max(dp[i], dp[i - c] + 1);
    }
    return dp[n];
}
int main() {
    int n, a, b, c;
    scanf("%d", &n);
    scanf("%d %d %d", &a, &b, &c);
    printf("%d\n", cutRibbon(n, a, b, c));
    return 0;
}

